import React, { useState, useEffect } from "react";

import "./HeroSlider.css";
import { Link } from "react-router-dom";

export default function HeroSlider() {

  //const [slides, setSlides] = useState([]);
  const [index, setIndex] = useState(0);


  const slides = [
    { "image": "/images/livingroom2.jpg", "title": " ", "url": "/", "text1": "LIVING ROOM ", "subtitle": " ", "title1": " " },
    { "image": "/images/livingroom3.jpg", "title": " ", "url": "/", "text1": " LIVING ROOM ", "subtitle": " ", "title1": " " },
    { "image": "/images/BEDROOM2.png", "title": " ", "url": "/", "text1": "BED ROOM ", "subtitle": " ", "title1": " " },
    { "image": "/images/BEDROOM1.png", "title": " ", "url": "/", "text1": " BED ROOM ", "subtitle": " ", "title1": " " },
    { "image": "/images/dinning1.png", "title": " ", "url": "/", "text1": "DINIG ROOM  ", "subtitle": " ", "title1": " " },
    { "image": "/images/dining2.png", "title": " ", "url": "/", "text1": "DINIG ROOM  ", "subtitle": " ", "title1": " " },
    
  ];

/* 
  useEffect(() => {

    api.get(API_URL + "/sliders")
      .then(res => {



        if (res.data.success === true) {

          //setSlides(res.data.slides);
          setYoutubeLink(res.data.youtube_link);
          setFacebookLink(res.data.facebook_link);
          setActivePlatform(res.data.active_platform);

        } else {


        }

      })
      .catch(err => {
        console.log(err);
      })

  }, []);
 */

  const next = () => {
    setIndex(prev => (prev + 1) % slides.length)
  }

  const prev = () => {
    setIndex(prev => prev === 0 ? slides.length - 1 : prev - 1)
  }


  useEffect(() => {

    if (slides.length === 0) return;

    const timer = setInterval(() => {
      next()
    }, 6000)

    return () => clearInterval(timer)

  }, [slides, index])


  /* ---------------------------
     Convert YouTube Link
  --------------------------- */

  const getYoutubeEmbed = (url) => {

    if (!url) return "";

    const regExp = /(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&]+)/;
    const match = url.match(regExp);

    return match
      ? `https://www.youtube.com/embed/${match[1]}?autoplay=1&mute=1`
      : url;
  };


  /* ---------------------------
     FACEBOOK LIVE
  --------------------------- */

  const getFacebookEmbed = (url) => {

    if (!url) return "";

    return `https://www.facebook.com/plugins/video.php?href=${encodeURIComponent(url)}&show_text=false&autoplay=true`;

  };




  /* ===============================
      NORMAL SLIDER (UNCHANGED)
  =============================== */

  if (slides.length === 0) {

    return (

      <div className="hero-loading">

        <div className="loading-slide">

          <div className="loading-image shimmer"></div>

          <div className="loading-content">

            <div className="loading-title shimmer"></div>

            <div className="loading-text shimmer"></div>

            <div className="loading-btn shimmer"></div>

          </div>

        </div>

      </div>

    )

  }

  return (

    <div className="hero-slider">

      {slides.map((slide, i) => (

        <div
          key={i}
          className={`slide ${i === index ? "active" : ""}`}
        >

          <div
            className="blur-bg"
            style={{
              backgroundImage: `url(${slide.image})`
            }}
          />

          <img
            src={slide.image}
            alt={slide.title}
            loading="lazy"
            className="main-image"
          />

         

          <div className="content">

            <h1>{slide.title1}</h1>

            <p>{slide.subtitle}</p>

            {slide.url != null && (

              <Link to={slide.url}>

                <button className="btn">
                  {slide.text1}
                </button>

              </Link>
            )

            }

          </div>

        </div>

      ))}

      <div className="arrow left" onClick={prev}>‹</div>
      <div className="arrow right" onClick={next}>›</div>

    </div>

  )

}