import React, { useState, useEffect } from "react";
import "./selectedProducts.css";

const categories = ["Living Room", "Dining Room", "Bedroom", "Royal Sets"];

const productsData = {
  "Living Room": [
    {
      name: "Nepal Sofa Set",
      price: "₦11,800,000.00",
      image: "https://images.unsplash.com/photo-1586023492125-27b2c045efd7",
    },
    {
      name: "Petra Modern Sofa Set",
      price: "₦11,800,000.00",
      image: "https://images.unsplash.com/photo-1505693416388-ac5ce068fe85",
    },
    {
      name: "Amber Sofa Set",
      price: "₦12,050,000.00",
      image: "https://images.unsplash.com/photo-1615873968403-89e068629265",
    },
  ],
  "Dining Room": [
    {
      name: "Classic Dining Set",
      price: "₦8,500,000.00",
      image: "/images/dining2.png",
    },
  ],
  Bedroom: [
    {
      name: "Luxury Bed Set",
      price: "₦9,200,000.00",
      image: "https://images.unsplash.com/photo-1505693416388-ac5ce068fe85",
    },
  ],
  "Royal Sets": [
    {
      name: "Royal Gold Sofa",
      price: "₦15,000,000.00",
      image: "https://images.unsplash.com/photo-1618220179428-22790b461013",
    },
  ],
};

const SelectedProducts = () => {
  const [activeCategory, setActiveCategory] = useState("Living Room");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    const timer = setTimeout(() => setLoading(false), 800);
    return () => clearTimeout(timer);
  }, [activeCategory]);

  return (
    <div className="furni-selected-container">
      <h2 className="furni-selected-title">Selected For You</h2>

      {/* Categories */}
      <div className="furni-category-wrapper">
        {categories.map((cat) => (
          <button
            key={cat}
            className={`furni-category-btn ${
              activeCategory === cat ? "active" : ""
            }`}
            onClick={() => setActiveCategory(cat)}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Products */}
      <div className="furni-products-grid">
        {loading
          ? Array(6)
              .fill(0)
              .map((_, i) => (
                <div className="furni-product-card skeleton" key={i}>
                  <div className="furni-product-image-wrapper shimmer"></div>
                  <div className="furni-product-info">
                    <div className="shimmer text-line"></div>
                    <div className="shimmer text-line short"></div>
                  </div>
                </div>
              ))
          : productsData[activeCategory].map((item, index) => (
              <div className="furni-product-card fade-in" key={index}>
                <div className="furni-product-image-wrapper">
                  <img
                    src={item.image}
                    alt={item.name}
                    loading="lazy"
                    className="furni-product-image"
                  />
                </div>

                <div className="furni-product-info">
                  <h4>{item.name}</h4>
                  {/* <p>{item.price}</p> */}
                </div>
              </div>
            ))}
      </div>
    </div>
  );
};

export default SelectedProducts;